export { toast } from "./toast-store";
export type { Toast, ToastPosition, ToastOptions } from "./toast-store";
export type { ToastVariant } from "./toast-variants";

export { Toaster } from "./toast-container";
export type { ToasterProps } from "./toast-container";

"use client";

import { cn } from "@/lib/utils";
import { Spinner } from "../spinner/spinner";
import type { Toast as ToastType, ToastPosition } from "./toast-store";
import { toastVariants, iconColors, icons, slideAnimations, positionToSide } from "./toast-variants";
import { useToastDismiss } from "./use-toast-dismiss";

interface ToastProps extends ToastType {
  position: ToastPosition;
  onDismiss: (id: string) => void;
  onRemove: (id: string) => void;
  dismissing?: boolean;
}

export function Toast({
  id,
  variant = "info",
  title,
  message,
  action,
  position,
  onDismiss,
  onRemove,
  dismissing,
}: ToastProps) {
  const { onAnimationEnd } = useToastDismiss(dismissing ?? false, id, onRemove);
  const animation = slideAnimations[positionToSide[position]][dismissing ? "out" : "in"];

  return (
    <div
      aria-atomic="true"
      className={cn("pointer-events-auto", toastVariants({ variant }), animation)}
      onAnimationEnd={onAnimationEnd}
    >
      <div className="flex items-center justify-between px-3 py-1.5 border-b border-border bg-secondary/40">
        <div className="flex items-center gap-2">
          <span className={cn("font-bold", iconColors[variant])} aria-hidden="true">
            {variant === "loading" ? <Spinner variant="braille" size="sm" gap="none" aria-hidden="true" /> : icons[variant]}
          </span>
          <span className="sr-only">{variant}:</span>
          <span className="text-xs font-bold uppercase tracking-tight text-foreground">
            {title}
          </span>
        </div>
        <button
          type="button"
          onClick={() => onDismiss(id)}
          className="p-1 min-h-6 min-w-6 flex items-center justify-center text-xs leading-none text-muted hover:text-foreground"
          aria-label={`Dismiss: ${title}`}
        >
          ✕
        </button>
      </div>
      {(message || action) && (
        <div className="p-3 text-sm flex items-center justify-between gap-2">
          {message && <span className="text-foreground/90">{message}</span>}
          {action && <span className="shrink-0">{action}</span>}
        </div>
      )}
    </div>
  );
}

"use client";

import type { FocusEvent } from "react";
import { cn } from "@/lib/utils";
import { useToastStore, dismiss, remove, pause, resume, type ToastPosition } from "./toast-store";
import { positionClasses } from "./toast-variants";
import { Toast } from "./toast";
import { useToastContainer } from "./use-toast-container";

function handleBlur(e: FocusEvent<HTMLDivElement>) {
  if (!(e.relatedTarget instanceof Node) || !e.currentTarget.contains(e.relatedTarget)) resume();
}

export interface ToasterProps {
  position?: ToastPosition;
}

export function Toaster({ position = "bottom-right" }: ToasterProps) {
  const { toasts, dismissingIds } = useToastStore();
  useToastContainer(toasts, dismissingIds);
  const hasToasts = toasts.length > 0;

  return (
    <div
      role="log"
      aria-label="Notifications"
      aria-live="polite"
      aria-atomic="false"
      aria-relevant="additions"
      onMouseEnter={hasToasts ? pause : undefined}
      onMouseLeave={hasToasts ? resume : undefined}
      onFocus={hasToasts ? pause : undefined}
      onBlur={hasToasts ? handleBlur : undefined}
      className={cn(
        "fixed z-50 flex gap-2 pointer-events-none",
        position.startsWith("top") ? "flex-col" : "flex-col-reverse",
        positionClasses[position],
      )}
    >
      {toasts.map((t) => (
        <Toast
          key={t.id}
          {...t}
          position={position}
          onDismiss={dismiss}
          onRemove={remove}
          dismissing={dismissingIds.has(t.id)}
        />
      ))}
    </div>
  );
}

import { cva, type VariantProps } from "class-variance-authority";
import type { ToastPosition } from "./toast-store";

export const toastVariants = cva("w-full border border-border bg-background shadow-2xl", {
  variants: {
    variant: {
      success: "border-success-border",
      error: "border-error-border",
      warning: "border-warning-border",
      info: "border-info-border",
      loading: "border-info-border",
    },
  },
  defaultVariants: {
    variant: "info",
  },
});

/** @see @diffgazer/core/schemas/ui ToastVariant (subset without "loading", used for app-level toast state) */
export type ToastVariant = NonNullable<VariantProps<typeof toastVariants>["variant"]>;

export const iconColors: Record<ToastVariant, string> = {
  success: "text-success-fg",
  error: "text-error-fg",
  warning: "text-warning-fg",
  info: "text-info-fg",
  loading: "text-info-fg",
};

export const icons: Record<Exclude<ToastVariant, "loading">, string> = {
  success: "✓",
  error: "✕",
  warning: "!",
  info: "i",
};

export const slideAnimations = {
  left:   { in: "motion-safe:animate-slide-in-left",   out: "motion-safe:animate-slide-out-left"   },
  right:  { in: "motion-safe:animate-slide-in-right",  out: "motion-safe:animate-slide-out-right"  },
  top:    { in: "motion-safe:animate-slide-in-top",    out: "motion-safe:animate-slide-out-top"    },
  bottom: { in: "motion-safe:animate-slide-in-bottom", out: "motion-safe:animate-slide-out-bottom" },
} as const;

export const positionToSide: Record<ToastPosition, keyof typeof slideAnimations> = {
  "top-left": "left",    "top-center": "top",      "top-right": "right",
  "bottom-left": "left", "bottom-center": "bottom", "bottom-right": "right",
};

export const positionClasses: Record<ToastPosition, string> = {
  "top-left": "top-4 left-4 right-4 sm:right-auto sm:left-8 sm:w-80",
  "top-center": "top-4 left-4 right-4 sm:inset-x-0 sm:mx-auto sm:w-80",
  "top-right": "top-4 left-4 right-4 sm:left-auto sm:right-8 sm:w-80",
  "bottom-left": "bottom-4 left-4 right-4 sm:right-auto sm:left-8 sm:w-80",
  "bottom-center": "bottom-4 left-4 right-4 sm:inset-x-0 sm:mx-auto sm:w-80",
  "bottom-right": "bottom-4 left-4 right-4 sm:left-auto sm:right-8 sm:w-80",
};

"use client";

import { useSyncExternalStore, type ReactNode } from "react";
import type { ToastVariant } from "./toast-variants";

export type ToastPosition =
  | "top-left"
  | "top-center"
  | "top-right"
  | "bottom-left"
  | "bottom-center"
  | "bottom-right";

export interface Toast {
  id: string;
  variant: ToastVariant;
  title: string;
  message?: string;
  duration?: number;
  action?: ReactNode;
}

export interface ToastOptions {
  title: string;
  variant?: ToastVariant;
  message?: string;
  /** Auto-dismiss delay in ms. When `action` is set and duration is omitted, the toast persists indefinitely (WCAG 2.2.1 — enough time). */
  duration?: number;
  action?: ReactNode;
  id?: string;
}

const DEFAULT_DURATION = 5000;
const MAX_TOASTS = 5;

interface StoreState {
  toasts: Toast[];
  dismissingIds: Set<string>;
}

const INITIAL_STATE: StoreState = { toasts: [], dismissingIds: new Set() };

interface TimerEntry {
  timeout: ReturnType<typeof setTimeout> | undefined;
  startedAt: number;
  remaining: number;
}

let state: StoreState = INITIAL_STATE;
const listeners = new Set<() => void>();
const timers = new Map<string, TimerEntry>();
let paused = false;

function emit() {
  for (const listener of listeners) listener();
}

function clearTimer(id: string) {
  const entry = timers.get(id);
  if (entry) {
    clearTimeout(entry.timeout);
    timers.delete(id);
  }
}

function subscribe(listener: () => void) {
  listeners.add(listener);
  return () => listeners.delete(listener);
}

function getSnapshot(): StoreState {
  return state;
}

function getServerSnapshot(): StoreState {
  return INITIAL_STATE;
}

function scheduleAutoDismiss(id: string, variant: ToastVariant, duration?: number) {
  if ((variant === "error" || variant === "loading") && duration === undefined) return;
  const resolved = duration ?? DEFAULT_DURATION;
  if (!Number.isFinite(resolved) || resolved <= 0) return;
  const entry: TimerEntry = {
    timeout: paused ? undefined : setTimeout(() => dismiss(id), resolved),
    startedAt: Date.now(),
    remaining: resolved,
  };
  timers.set(id, entry);
}

function resolveNextToasts(current: Toast[], incoming: Toast): Toast[] {
  const existingIdx = current.findIndex((t) => t.id === incoming.id);
  if (existingIdx >= 0) return current.map((t) => (t.id === incoming.id ? incoming : t));

  const all = [...current, incoming];
  const evicted = all.slice(0, Math.max(0, all.length - MAX_TOASTS));
  for (const t of evicted) clearTimer(t.id);
  return all.slice(-MAX_TOASTS);
}

function create(options: ToastOptions): string {
  const id = options.id ?? crypto.randomUUID();
  const variant = options.variant ?? "info";
  const newToast: Toast = {
    id, variant,
    title: options.title,
    message: options.message,
    duration: options.duration,
    action: options.action,
  };

  clearTimer(id);
  const nextDismissing = new Set(state.dismissingIds);
  nextDismissing.delete(id);
  if (!options.action || options.duration !== undefined) {
    scheduleAutoDismiss(id, variant, options.duration);
  }

  const nextToasts = resolveNextToasts(state.toasts, newToast);
  const nextIds = new Set(nextToasts.map(t => t.id));
  for (const dismissId of nextDismissing) {
    if (!nextIds.has(dismissId)) nextDismissing.delete(dismissId);
  }

  state = { toasts: nextToasts, dismissingIds: nextDismissing };
  emit();
  return id;
}

export function dismiss(id?: string) {
  if (id) {
    state = {
      toasts: state.toasts,
      dismissingIds: new Set(state.dismissingIds).add(id),
    };
  } else {
    state = { toasts: state.toasts, dismissingIds: new Set(state.toasts.map(t => t.id)) };
  }
  emit();
}

export function remove(id: string) {
  clearTimer(id);
  const nextDismissing = new Set(state.dismissingIds);
  nextDismissing.delete(id);
  state = {
    toasts: state.toasts.filter((t) => t.id !== id),
    dismissingIds: nextDismissing,
  };
  emit();
}

export function pause() {
  if (paused) return;
  paused = true;
  for (const [, entry] of timers) {
    clearTimeout(entry.timeout);
    entry.remaining = Math.max(0, entry.remaining - (Date.now() - entry.startedAt));
  }
}

export function resume() {
  if (!paused) return;
  paused = false;
  for (const [id, entry] of timers) {
    entry.startedAt = Date.now();
    entry.timeout = setTimeout(() => dismiss(id), entry.remaining);
  }
}

type VariantMethod = (title: string, options?: Omit<ToastOptions, "variant" | "title">) => string;

interface ToastFn extends Record<ToastVariant, VariantMethod> {
  (title: string, options?: Omit<ToastOptions, "title">): string;
  dismiss: (id?: string) => void;
  promise: <T>(
    promise: Promise<T>,
    options: {
      loading: string;
      success: string | ((data: T) => string);
      error: string | ((err: unknown) => string);
    },
  ) => Promise<T>;
}

function variantMethod(variant: ToastVariant): VariantMethod {
  return (title, options) => create({ ...options, title, variant });
}

function promiseToast<T>(
  promise: Promise<T>,
  options: {
    loading: string;
    success: string | ((data: T) => string);
    error: string | ((err: unknown) => string);
  },
): Promise<T> {
  const id = create({ title: options.loading, variant: "loading" });

  return promise.then(
    (data) => {
      const title = typeof options.success === "function" ? options.success(data) : options.success;
      create({ id, title, variant: "success" });
      return data;
    },
    (err) => {
      const title = typeof options.error === "function" ? options.error(err) : options.error;
      create({ id, title, variant: "error" });
      throw err;
    },
  );
}

export const toast: ToastFn = Object.assign(
  (title: string, options?: Omit<ToastOptions, "title">) => create({ ...options, title }),
  {
    success: variantMethod("success"),
    error: variantMethod("error"),
    warning: variantMethod("warning"),
    info: variantMethod("info"),
    loading: variantMethod("loading"),
    dismiss,
    promise: promiseToast,
  },
);

export function useToastStore(): StoreState {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useRef, useEffect, useEffectEvent } from "react";

// Fallback timeout for reduced-motion: onAnimationEnd won't fire when
// motion-safe:animate-* classes are suppressed by prefers-reduced-motion.
const DISMISS_FALLBACK_MS = 200;

export function useToastDismiss(
  dismissing: boolean,
  id: string,
  onRemove: (id: string) => void,
) {
  const removedRef = useRef(false);
  const stableOnRemove = useEffectEvent(onRemove);

  useEffect(() => {
    if (!dismissing) {
      removedRef.current = false;
      return;
    }
    const timer = setTimeout(() => {
      if (!removedRef.current) {
        removedRef.current = true;
        stableOnRemove(id);
      }
    }, DISMISS_FALLBACK_MS);
    return () => clearTimeout(timer);
  }, [dismissing, id]);

  return {
    onAnimationEnd: () => {
      if (dismissing && !removedRef.current) {
        removedRef.current = true;
        stableOnRemove(id);
      }
    },
  };
}

"use client";

import { useEffect, useEffectEvent } from "react";
import type { Toast } from "./toast-store";
import { dismiss, pause, resume } from "./toast-store";

export function useToastContainer(
  toasts: Toast[],
  dismissingIds: Set<string>,
) {
  const handleEscape = useEffectEvent(() => {
    const last = toasts.findLast((t) => !dismissingIds.has(t.id));
    if (last) dismiss(last.id);
  });

  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (e.defaultPrevented) return;
      if (e.key === "Escape") handleEscape();
    }
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, []);

  useEffect(() => {
    if (!document.hidden) resume();
    function onVisibilityChange() {
      if (document.hidden) pause();
      else resume();
    }
    document.addEventListener("visibilitychange", onVisibilityChange);
    return () => {
      document.removeEventListener("visibilitychange", onVisibilityChange);
      resume();
    };
  }, []);
}
